function AesDecode(data) {
	    const { java } = this;    
	    let key = java.base64DecodeToByteArray("le95G3hnFDJsBE+1/v9eYw==");
    let iv = java.base64DecodeToByteArray("IvswQFEUdKYf+d1wKpYLTg==");
    let con = java.createSymmetricCrypto("AES/CBC/PKCS7Padding", key, iv).decryptStr(data);
   return con;
}

function gk(t, n) {
    let result = "";
    for (let i = 0; i < 20; i++) {
        var charCode = t[i].charCodeAt(0) + Number(n[i]);
        result += String.fromCharCode(charCode);
    }
    for (let i = 20; i < t.length; i++) {
        var charCode = t[i].charCodeAt(0) + Number(n[i - 20]);
        result += String.fromCharCode(charCode);
    }
    return result;
}

function gi(t, n) {
    let result = "";
    for (let i = 20; i > 4; i--) {
        var charCode = t[i].charCodeAt(0) + Number(n[i - 1]);
        result += String.fromCharCode(charCode);
    }
    return result;
}


function d(e, t, n) {
	const { java } = this;    
    var key = gk(t, n);
    var iv = gi(t, n);    
    var e = (e + "").replace(/\n/g, "");

    var con = java.createSymmetricCrypto("AES/CBC/PKCS7Padding", key, iv).decryptStr(e);
   return con;
}

