    };
 push("🌹排行🌹",null,1)
    for(i in b){
        title=b[i].text()
        url=b[i].attr("href")
  url=String(url).replace("1/","{{page}}/").replace("1.html","{{page}}.html")
        size=0.25;
        push(title,url,size)
    }
push("🌹全本🌹","/full/{{page}}/",1)

}else{
  java.toast("发现列表获取失败！")
}

JSON.stringify(sort)

